// Parse Stripe billing event. Handles invoice.payment_failed, invoice.payment_succeeded,
// customer.subscription.deleted.
const raw = $input.first().json;
const body = raw.body || raw;
const event = body && body.type ? body : (body.event || body);
const type = event.type || '';
const obj = (event.data && event.data.object) ? event.data.object : (event.object || {});

function intervalFromPrice(price) {
  if (!price || !price.recurring) return '';
  const i = price.recurring.interval, c = price.recurring.interval_count || 1;
  if (i === 'week' && c === 1) return 'weekly';
  if (i === 'week' && c === 2) return 'fortnightly';
  if (i === 'month' && c === 1) return 'monthly';
  if (i === 'month' && c === 3) return 'quarterly';
  return i + (c > 1 ? ('x' + c) : '');
}

let price = null;
if (obj.lines && obj.lines.data && obj.lines.data[0]) price = obj.lines.data[0].price || obj.lines.data[0].plan;
if (!price && obj.items && obj.items.data && obj.items.data[0]) price = obj.items.data[0].price || obj.items.data[0].plan;
const plan_interval = intervalFromPrice(price);
const gracePeriods = { weekly: 1, fortnightly: 2, monthly: 3, quarterly: 5 };
const grace_days = gracePeriods[plan_interval] || 3;

// mobile_number, orderId, numberId resolve from the subscriber store at live integration; metadata used if present.
const md = obj.metadata || {};
const out = {
  event_type: type,
  stripe_subscription_id: obj.subscription || obj.id || '',
  stripe_customer_id: obj.customer || '',
  plan_interval: plan_interval,
  grace_days: grace_days,
  attempt_count: obj.attempt_count || 0,
  was_retry: (obj.attempt_count || 0) > 1,
  mobile_number: String(md.mobile || md.plan_1_mobile || '').replace(/[^0-9]/g, '').slice(-10),
  prison_name: md.prison_name || md.plan_1_prison || '',
  orderId: md.voipline_order_id || '',
  numberId: md.voipline_number_id || '',
  day: 0
};
return [{ json: out }];

// Day 0 (MOCK): pause 3CX forwarding so the number stops ringing while payment is outstanding.
const d = $json;
return [{ json: { ...d, threeCX_paused: { mocked: true, success: true, action: 'disable_forwarding' } } }];

// Day 0 payment-failed SMS (ClickSend dedicated number - two-way capable for support).
const helpers = this.helpers;
const d = $json;
const to = d.mobile_number ? ('+61' + d.mobile_number.replace(/^0/, '')) : $env.OWNER_MOBILE;
const text = 'Your Prisoncall payment failed. Please update your payment method to keep your number active.';
const auth = 'Basic ' + Buffer.from($env.CLICKSEND_USERNAME + ':' + $env.CLICKSEND_API_KEY).toString('base64');
const resp = await helpers.httpRequest({ method: 'POST', url: 'https://rest.clicksend.com/v3/sms/send', headers: { Authorization: auth, 'Content-Type': 'application/json' }, body: { messages: [{ source: 'n8n', from: $env.CLICKSEND_DEDICATED_NUMBER, to: to, body: text }] }, json: true });
return [{ json: { ...d, sms_failed: resp } }];

// Advance one day inside the grace period and decide whether more daily reminders are due.
const d = $json;
d.day = (d.day || 0) + 1;
d.more = d.day < d.grace_days;
return [{ json: d }];

// Daily reminder during the grace period, then loop back to wait another day.
const helpers = this.helpers;
const d = $json;
const to = d.mobile_number ? ('+61' + d.mobile_number.replace(/^0/, '')) : $env.OWNER_MOBILE;
const text = 'Reminder: your Prisoncall payment is still outstanding (day ' + d.day + ' of ' + d.grace_days + '). Please update your payment method to keep your number active.';
const auth = 'Basic ' + Buffer.from($env.CLICKSEND_USERNAME + ':' + $env.CLICKSEND_API_KEY).toString('base64');
const resp = await helpers.httpRequest({ method: 'POST', url: 'https://rest.clicksend.com/v3/sms/send', headers: { Authorization: auth, 'Content-Type': 'application/json' }, body: { messages: [{ source: 'n8n', from: $env.CLICKSEND_DEDICATED_NUMBER, to: to, body: text }] }, json: true });
return [{ json: { ...d, last_reminder: resp } }];

// Grace period expired (MOCK): delete the 3CX extension.
const d = $json;
return [{ json: { ...d, threeCX_deleted: { mocked: true, success: true, action: 'delete_extension', extension: d.threeCX_extension || null } } }];

// Release DID - 2-STEP (VoipLine enforces order, returns 422 if step 1 skipped).
// Step 1 (MOCK): remove DID from the PBX inbound number object.
// Step 2: VoipLine release endpoint via the Cloudflare Worker proxy.
const helpers = this.helpers;
const d = $json;
const PROXY = 'https://workers.prisoncall.com.au/voipline-proxy';
const orderId = d.orderId || d.order_id || '';
const numberId = d.numberId || d.number_id || '';
let release = { skipped: true, reason: 'orderId/numberId not resolved - resolve from /api/customer/numbers/active or subscriber store at live integration' };
if (orderId && numberId) {
  release = await helpers.httpRequest({ method: 'POST', url: PROXY, headers: { 'X-Proxy-Secret': $env.VOIPLINE_PROXY_SECRET, 'X-VoipLine-Path': '/api/customer/order/' + orderId + '/number/' + numberId + '/release', 'X-VoipLine-Method': 'PUT', 'Content-Type': 'application/json' }, body: {}, json: true });
}
return [{ json: { ...d, pbx_inbound_removed_mock: true, did_release: release } }];

// Cancel the Stripe subscription after the grace period fully expires.
const helpers = this.helpers;
const d = $json;
let result = { skipped: true };
if (d.stripe_subscription_id) {
  result = await helpers.httpRequest({ method: 'DELETE', url: 'https://api.stripe.com/v1/subscriptions/' + d.stripe_subscription_id, headers: { Authorization: 'Bearer ' + $env.STRIPE_SECRET_KEY } });
}
return [{ json: { ...d, stripe_cancelled: result } }];

// Cancellation received (MOCK): pause 3CX forwarding, hold DID + extension intact for reactivation.
const d = $json;
return [{ json: { ...d, threeCX_paused: { mocked: true, success: true, action: 'disable_forwarding' } } }];

// Cancellation SMS - 5-day reactivation window.
const helpers = this.helpers;
const d = $json;
const to = d.mobile_number ? ('+61' + d.mobile_number.replace(/^0/, '')) : $env.OWNER_MOBILE;
const text = 'Your Prisoncall subscription has been cancelled. You have 5 days to reactivate.';
const auth = 'Basic ' + Buffer.from($env.CLICKSEND_USERNAME + ':' + $env.CLICKSEND_API_KEY).toString('base64');
const resp = await helpers.httpRequest({ method: 'POST', url: 'https://rest.clicksend.com/v3/sms/send', headers: { Authorization: auth, 'Content-Type': 'application/json' }, body: { messages: [{ source: 'n8n', from: $env.CLICKSEND_DEDICATED_NUMBER, to: to, body: text }] }, json: true });
return [{ json: { ...d, sms_cancelled: resp } }];

// Day 5 (MOCK): delete the 3CX extension after the reactivation window closes.
const d = $json;
return [{ json: { ...d, threeCX_deleted: { mocked: true, success: true, action: 'delete_extension' } } }];

// Release DID - 2-step (mock PBX removal, then VoipLine release via proxy).
const helpers = this.helpers;
const d = $json;
const PROXY = 'https://workers.prisoncall.com.au/voipline-proxy';
const orderId = d.orderId || '';
const numberId = d.numberId || '';
let release = { skipped: true, reason: 'orderId/numberId not resolved at build time' };
if (orderId && numberId) {
  release = await helpers.httpRequest({ method: 'POST', url: PROXY, headers: { 'X-Proxy-Secret': $env.VOIPLINE_PROXY_SECRET, 'X-VoipLine-Path': '/api/customer/order/' + orderId + '/number/' + numberId + '/release', 'X-VoipLine-Method': 'PUT', 'Content-Type': 'application/json' }, body: {}, json: true });
}
return [{ json: { ...d, pbx_inbound_removed_mock: true, did_release: release } }];

// Payment recovered (MOCK): re-enable 3CX forwarding on the same extension.
const d = $json;
return [{ json: { ...d, threeCX_reenabled: { mocked: true, success: true, action: 'enable_forwarding' } } }];

// Payment success SMS after a previous failure.
const helpers = this.helpers;
const d = $json;
const to = d.mobile_number ? ('+61' + d.mobile_number.replace(/^0/, '')) : $env.OWNER_MOBILE;
const text = 'Your Prisoncall payment was successful. Your number is active again.';
const auth = 'Basic ' + Buffer.from($env.CLICKSEND_USERNAME + ':' + $env.CLICKSEND_API_KEY).toString('base64');
const resp = await helpers.httpRequest({ method: 'POST', url: 'https://rest.clicksend.com/v3/sms/send', headers: { Authorization: auth, 'Content-Type': 'application/json' }, body: { messages: [{ source: 'n8n', from: $env.CLICKSEND_DEDICATED_NUMBER, to: to, body: text }] }, json: true });
return [{ json: { ...d, sms_recovered: resp } }];
